    validateCounterAmount: function (offerId, value, minAmount, maxAmount) {
        const errorEl = document.getElementById('counter-error-' + offerId);
        if (!errorEl) return true;
        const val = parseFloat(value);
        if (isNaN(val) || val <= 0) {
            errorEl.textContent = 'Must be greater than $0';
            errorEl.style.display = 'block';
            return false;
        } else if (val < minAmount) {
            errorEl.textContent = 'Must be >= offer ($' + minAmount.toFixed(0) + ')';
            errorEl.style.display = 'block';
            return false;
        } else if (val > maxAmount * 1.5) {
            errorEl.textContent = 'Exceeds 150% of list price';
            errorEl.style.display = 'block';
            return false;
        } else {
            errorEl.style.display = 'none';
            return true;
        }
    },

