    validateTxAmount: function (input) {
        const errorEl = document.getElementById('tx-amount-error');
        const val = parseFloat(input.value);
        if (isNaN(val) || val <= 0) {
            errorEl.textContent = 'Amount must be greater than $0.00';
            errorEl.style.display = 'block';
            input.style.borderColor = 'var(--error)';
        } else if (val > 99999.99) {
            errorEl.textContent = 'Amount cannot exceed $99,999.99';
            errorEl.style.display = 'block';
            input.style.borderColor = 'var(--error)';
        } else if (input.value.includes('.') && input.value.split('.')[1].length > 2) {
            errorEl.textContent = 'Maximum 2 decimal places';
            errorEl.style.display = 'block';
            input.style.borderColor = 'var(--error)';
        } else {
            errorEl.style.display = 'none';
            input.style.borderColor = '';
        }
    },

    exportTransactions: function (format) {
        const activeTab = store.state.transactionsTab || 'purchases';
        let purchases = store.state.purchases || [];
        let sales = store.state.sales || [];
        const txPlatformFilter = store.state.txPlatformFilter || 'all';
        const txDateFilter = store.state.txDateFilter || 'all';
        const txSearchQuery = store.state.txSearchQuery || '';
        const txStatusFilter = store.state.txStatusFilter || 'all';
        const txBuyerFilter = store.state.txBuyerFilter || '';
        const txAmountMin = parseFloat(store.state.txAmountMin) || 0;
        const txAmountMax = parseFloat(store.state.txAmountMax) || 0;
        const txCategoryFilter = store.state.txCategoryFilter || 'all';

        // Apply same filters as page renderer
        if (txSearchQuery) {
            const q = txSearchQuery.toLowerCase();
            purchases = purchases.filter(
                (p) =>
                    (p.vendor || p.vendor_name || '').toLowerCase().includes(q) ||
                    (p.item || '').toLowerCase().includes(q),
            );
            sales = sales.filter(
                (s) =>
                    (s.listing_title || s.inventory_title || '').toLowerCase().includes(q) ||
                    (s.platform || '').toLowerCase().includes(q),
            );
        }
        if (txPlatformFilter !== 'all') sales = sales.filter((s) => s.platform === txPlatformFilter);
        if (txStatusFilter !== 'all') sales = sales.filter((s) => (s.status || 'completed') === txStatusFilter);
        if (txBuyerFilter) {
            const bq = txBuyerFilter.toLowerCase();
            sales = sales.filter((s) => (s.buyer_username || s.buyer_name || '').toLowerCase().includes(bq));
        }
        if (txDateFilter !== 'all') {
            const now = new Date();
            let cutoff;
            if (txDateFilter === '7d' || txDateFilter === 'week') cutoff = new Date(now - 7 * 86400000);
            else if (txDateFilter === '30d' || txDateFilter === 'month') cutoff = new Date(now - 30 * 86400000);
            else if (txDateFilter === '90d' || txDateFilter === 'quarter') cutoff = new Date(now - 90 * 86400000);
            else if (txDateFilter === 'today') {
                cutoff = new Date();
                cutoff.setHours(0, 0, 0, 0);
            }
            if (cutoff) {
                purchases = purchases.filter((p) => new Date(p.date || p.purchase_date || p.created_at) >= cutoff);
                sales = sales.filter((s) => new Date(s.created_at) >= cutoff);
            }
        }
        if (txAmountMin > 0) {
            purchases = purchases.filter((p) => (p.amount || p.total_amount || 0) >= txAmountMin);
            sales = sales.filter((s) => (s.sale_price || 0) >= txAmountMin);
        }
        if (txAmountMax > 0) {
            purchases = purchases.filter((p) => (p.amount || p.total_amount || 0) <= txAmountMax);
            sales = sales.filter((s) => (s.sale_price || 0) <= txAmountMax);
        }
        if (txCategoryFilter !== 'all')
            purchases = purchases.filter((p) => (p.category || 'Other') === txCategoryFilter);

        const useXlsx = format === 'xlsx';
        const count = activeTab === 'purchases' ? purchases.length : sales.length;

        function xmlEsc(v) {
            return String(v == null ? '' : v)
                .replace(/&/g, '&amp;')
                .replace(/</g, '&lt;')
                .replace(/>/g, '&gt;')
                .replace(/"/g, '&quot;');
        }
        function xlRow(cells) {
            return (
                '<Row>' +
                cells
                    .map((c) => {
                        const isNum =
                            typeof c === 'number' ||
                            (typeof c === 'string' && c !== '' && !isNaN(Number(c)) && c.trim() !== '');
                        return isNum
                            ? `<Cell><Data ss:Type="Number">${xmlEsc(c)}</Data></Cell>`
                            : `<Cell><Data ss:Type="String">${xmlEsc(c)}</Data></Cell>`;
                    })
                    .join('') +
                '</Row>'
            );
        }
        function buildXml(headers, rows) {
            const rowsXml = [xlRow(headers), ...rows.map(xlRow)].join('');
            return `<?xml version="1.0"?><?mso-application progid="Excel.Sheet"?><Workbook xmlns="urn:schemas-microsoft-com:office:spreadsheet" xmlns:ss="urn:schemas-microsoft-com:office:spreadsheet"><Worksheet ss:Name="Sheet1"><Table>${rowsXml}</Table></Worksheet></Workbook>`;
        }

        let content, filename, mimeType;
        if (activeTab === 'purchases') {
            const headers = ['Date', 'Vendor', 'Item', 'Amount', 'Category', 'Payment Method'];
            const rows = purchases.map((p) => [
                p.purchase_date || p.date || '',
                p.vendor_name || p.vendor || '',
                p.item || '',
                p.total_amount || p.amount || 0,
                p.category || '',
                p.payment_method || '',
            ]);
            if (useXlsx) {
                content = buildXml(headers, rows);
                filename = `purchases_export_${count}.xlsx`;
                mimeType = 'application/vnd.ms-excel';
            } else {
                content =
                    headers.join(',') +
                    '\n' +
                    purchases
                        .map(
                            (p) =>
                                `"${p.purchase_date || p.date || ''}","${(p.vendor_name || p.vendor || '').replace(/"/g, '""')}","${(p.item || '').replace(/"/g, '""')}",${p.total_amount || p.amount || 0},"${p.category || ''}","${p.payment_method || ''}"`,
                        )
                        .join('\n');
                filename = `purchases_export_${count}.csv`;
                mimeType = 'text/csv';
            }
        } else {
            const headers = ['Date', 'Item', 'Platform', 'Sale Price', 'Fees', 'Profit', 'Buyer', 'Status'];
            const rows = sales.map((s) => [
                s.created_at || '',
                s.listing_title || s.inventory_title || '',
                s.platform || '',
                s.sale_price || 0,
                s.platform_fee || 0,
                s.net_profit || 0,
                s.buyer_username || s.buyer_name || '',
                s.status || 'completed',
            ]);
            if (useXlsx) {
                content = buildXml(headers, rows);
                filename = `sales_export_${count}.xlsx`;
                mimeType = 'application/vnd.ms-excel';
            } else {
                content =
                    headers.join(',') +
                    '\n' +
                    sales
                        .map(
                            (s) =>
                                `"${s.created_at || ''}","${(s.listing_title || s.inventory_title || '').replace(/"/g, '""')}","${s.platform || ''}",${s.sale_price || 0},${s.platform_fee || 0},${s.net_profit || 0},"${(s.buyer_username || s.buyer_name || '').replace(/"/g, '""')}","${s.status || 'completed'}"`,
                        )
                        .join('\n');
                filename = `sales_export_${count}.csv`;
                mimeType = 'text/csv';
            }
        }

        const blob = new Blob([content], { type: mimeType });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = filename;
        a.click();
        URL.revokeObjectURL(url);
        toast.success(`Exported ${count} ${activeTab} to ${filename}`);
    },

