    executeSplitTransaction: async function (txId, originalAmount) {
        const rows = document.querySelectorAll('.split-row');
        const splits = [];
        rows.forEach((row) => {
            const desc = row.querySelector('[data-split-desc]')?.value || '';
            const amt = parseFloat(row.querySelector('[data-split-amt]')?.value) || 0;
            const cat = row.querySelector('[data-split-cat]')?.value || 'Other';
            if (amt > 0) splits.push({ description: desc, amount: amt, category: cat });
        });

        const total = splits.reduce((s, p) => s + p.amount, 0);
        if (Math.abs(total - originalAmount) > 0.01) {
            toast.error(`Split total (C$${total.toFixed(2)}) must equal original (C$${originalAmount.toFixed(2)})`);
            return;
        }

        try {
            await api.post(`/financials/transactions/${txId}/split`, { splits });
            toast.success('Transaction split successfully');
            modals.close();
            renderApp(window.pages.transactions());
        } catch (err) {
            toast.error('Split failed: ' + (err.message || 'Unknown error'));
        }
    },

