    addOrderNote: function (orderId) {
        const textarea = document.getElementById('new-order-note');
        const content = textarea?.value?.trim();
        if (!content) {
            toast.error('Please enter a note');
            return;
        }

        const user = store.state.user || {};
        const newNote = {
            id: Date.now().toString(),
            content: content,
            author: user.full_name || user.username || 'You',
            timestamp: new Date().toISOString(),
        };

        const allNotes = store.state.orderNotes || {};
        const orderNotes = allNotes[orderId] || [];
        allNotes[orderId] = [...orderNotes, newNote];
        store.setState({ orderNotes: allNotes });

        // Refresh the modal content
        this.showOrderNotes(orderId);
        toast.success('Note added');
    },

    deleteOrderNote: async function (orderId, noteId) {
        if (!(await modals.confirm('Delete this note?', { danger: true }))) return;

        const allNotes = store.state.orderNotes || {};
        const orderNotes = allNotes[orderId] || [];
        allNotes[orderId] = orderNotes.filter((n) => n.id !== noteId);
        store.setState({ orderNotes: allNotes });

        // Refresh the modal content
        this.showOrderNotes(orderId);
        toast.info('Note deleted');
    },

