    applyShippingPreset: function (preset) {
        const presets = {
            envelope: { weight: 0.3, length: 12, width: 9, height: 0.5 },
            small: { weight: 1, length: 8, width: 6, height: 4 },
            medium: { weight: 3, length: 12, width: 9, height: 6 },
            large: { weight: 5, length: 18, width: 12, height: 8 },
            poly: { weight: 0.5, length: 14, width: 10, height: 2 },
        };

        const p = presets[preset];
        if (p) {
            const weightEl = document.getElementById('ship-weight');
            const lengthEl = document.getElementById('ship-length');
            const widthEl = document.getElementById('ship-width');
            const heightEl = document.getElementById('ship-height');
            if (weightEl) weightEl.value = p.weight;
            if (lengthEl) lengthEl.value = p.length;
            if (widthEl) widthEl.value = p.width;
            if (heightEl) heightEl.value = p.height;
            handlers.updateShippingCalc();
            toast.success(`Applied ${preset} preset`);
        }
    },

    updateShippingCalc: function () {
        const weight = parseFloat(document.getElementById('ship-weight')?.value) || 1;
        const length = parseFloat(document.getElementById('ship-length')?.value) || 12;
        const width = parseFloat(document.getElementById('ship-width')?.value) || 9;
        const height = parseFloat(document.getElementById('ship-height')?.value) || 4;

        // Calculate dimensional weight (L x W x H / 139 for most carriers)
        const dimWeight = (length * width * height) / 139;
        const billableWeight = Math.max(weight, dimWeight);

        // Carrier rate estimates (simplified - real world would use API)
        const rates = [
            { carrier: 'USPS', service: 'First Class', rate: weight <= 1 ? 4.5 : null, days: '2-5' },
            { carrier: 'USPS', service: 'Priority Mail', rate: 8.5 + billableWeight * 0.5, days: '1-3' },
            { carrier: 'USPS', service: 'Ground Advantage', rate: 5.5 + billableWeight * 0.3, days: '2-5' },
            { carrier: 'UPS', service: 'Ground', rate: 9.5 + billableWeight * 0.8, days: '1-5' },
            { carrier: 'UPS', service: '2nd Day Air', rate: 18.0 + billableWeight * 1.5, days: '2' },
            { carrier: 'FedEx', service: 'Ground', rate: 9.0 + billableWeight * 0.75, days: '1-5' },
            { carrier: 'FedEx', service: 'Express Saver', rate: 16.0 + billableWeight * 1.2, days: '3' },
            { carrier: 'Pirate Ship', service: 'Simple Export', rate: 7.5 + billableWeight * 0.4, days: '2-5' },
        ].filter((r) => r.rate !== null);

        // Sort by price
        rates.sort((a, b) => a.rate - b.rate);

        const estimatesEl = document.getElementById('shipping-estimates');
        if (estimatesEl) {
            // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
            estimatesEl.innerHTML = sanitizeHTML(
                rates
                    .map(
                        (r, i) => `
                <div class="shipping-rate-card ${i === 0 ? 'best-rate' : ''}">
                    ${i === 0 ? '<span class="best-badge">Best Value</span>' : ''}
                    <div class="rate-carrier">${r.carrier}</div>
                    <div class="rate-service">${r.service}</div>
                    <div class="rate-price">C$${r.rate.toFixed(2)}</div>
                    <div class="rate-days">${r.days} days</div>
                </div>
            `,
                    )
                    .join(''),
            );
        }

        const dimEl = document.getElementById('dim-weight-info');
        if (dimEl) {
            // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
            dimEl.innerHTML = sanitizeHTML(`
                <div class="dim-weight-row">
                    <span>Actual Weight:</span>
                    <strong>${weight.toFixed(1)} lbs</strong>
                </div>
                <div class="dim-weight-row">
                    <span>Dimensional Weight:</span>
                    <strong>${dimWeight.toFixed(1)} lbs</strong>
                </div>
                <div class="dim-weight-row billable">
                    <span>Billable Weight:</span>
                    <strong>${billableWeight.toFixed(1)} lbs</strong>
                    ${dimWeight > weight ? '<span class="dim-warning">(DIM weight applies)</span>' : ''}
                </div>
            `);
        }
    },

