    updateFeeCalculation: function () {
        const price = parseFloat(document.getElementById('fee-sale-price')?.value) || 0;

        const platforms = [
            { name: 'eBay', baseFee: 12.9, paymentFee: 2.9, paymentFixed: 0.3 },
            { name: 'Poshmark', baseFee: 20, paymentFee: 0, paymentFixed: 0 },
            { name: 'Depop', baseFee: 10, paymentFee: 2.9, paymentFixed: 0.3 },
            { name: 'Facebook', baseFee: 5, paymentFee: 2.9, paymentFixed: 0.3 },
            { name: 'Whatnot', baseFee: 8, paymentFee: 0, paymentFixed: 0 },
        ];

        platforms.forEach((p) => {
            let totalFee =
                (price * p.baseFee) / 100 + (price * p.paymentFee) / 100 + p.paymentFixed + (p.listingFee || 0);

            // Poshmark special: C$2.95 flat fee under C$15
            if (p.name === 'Poshmark' && price < 15) {
                totalFee = 2.95;
            }

            // Facebook minimum C$0.40
            if (p.name === 'Facebook') {
                totalFee = Math.max(0.4, totalFee);
            }

            const netPayout = price - totalFee;
            const card = document.querySelector(`.fee-platform-card[data-platform="${p.name.toLowerCase()}"]`);
            if (card) {
                card.querySelector('.platform-net').textContent = 'C$' + netPayout.toFixed(2);
                card.querySelector('.platform-fee').textContent = '-C$' + totalFee.toFixed(2) + ' fees';
            }
        });
    },

