    generateCustomReport: function () {
        const reportType = document.getElementById('reportType')?.value || 'sales-summary';
        const reportFormat = document.getElementById('reportFormat')?.value || 'csv';
        const startDate = document.getElementById('reportStartDate')?.value;
        const endDate = document.getElementById('reportEndDate')?.value;

        let data = [];
        let headers = [];
        let filename = '';

        switch (reportType) {
            case 'sales-summary':
                headers = ['Date', 'Item', 'Platform', 'Sale Price', 'Fees', 'Profit'];
                data = (store.state.sales || [])
                    .filter((s) => {
                        if (startDate && new Date(s.created_at) < new Date(startDate)) return false;
                        if (endDate && new Date(s.created_at) > new Date(endDate)) return false;
                        return true;
                    })
                    .map((s) => [
                        new Date(s.created_at).toLocaleDateString(),
                        s.listing_title || s.inventory_title || 'N/A',
                        s.platform || 'N/A',
                        (s.sale_price || 0).toFixed(2),
                        (s.platform_fee || 0).toFixed(2),
                        (s.net_profit || 0).toFixed(2),
                    ]);
                filename = 'sales_summary';
                break;

            case 'inventory-valuation':
                headers = ['SKU', 'Title', 'Category', 'Cost', 'List Price', 'Quantity', 'Total Value'];
                data = (store.state.inventory || []).map((i) => [
                    i.sku || 'N/A',
                    i.title || 'N/A',
                    i.category || 'N/A',
                    (i.cost_price || 0).toFixed(2),
                    (i.listing_price || 0).toFixed(2),
                    i.quantity || 1,
                    ((i.listing_price || 0) * (i.quantity || 1)).toFixed(2),
                ]);
                filename = 'inventory_valuation';
                break;

            case 'platform-comparison':
                headers = ['Platform', 'Total Sales', 'Revenue', 'Fees', 'Net Profit', 'Avg Sale'];
                const platforms = ['poshmark', 'ebay', 'whatnot', 'depop', 'shopify', 'facebook'];
                data = platforms.map((p) => {
                    const platformSales = (store.state.sales || []).filter((s) => s.platform === p);
                    const revenue = platformSales.reduce((sum, s) => sum + (s.sale_price || 0), 0);
                    const fees = platformSales.reduce((sum, s) => sum + (s.platform_fee || 0), 0);
                    const profit = platformSales.reduce((sum, s) => sum + (s.net_profit || 0), 0);
                    return [
                        p.charAt(0).toUpperCase() + p.slice(1),
                        platformSales.length,
                        revenue.toFixed(2),
                        fees.toFixed(2),
                        profit.toFixed(2),
                        platformSales.length > 0 ? (revenue / platformSales.length).toFixed(2) : '0.00',
                    ];
                });
                filename = 'platform_comparison';
                break;

            case 'profit-loss':
                const sales = store.state.sales || [];
                const purchases = store.state.purchases || [];
                const totalRevenue = sales.reduce((sum, s) => sum + (s.sale_price || 0), 0);
                const totalCOGS = sales.reduce((sum, s) => sum + (s.item_cost || 0), 0);
                const totalFees = sales.reduce((sum, s) => sum + (s.platform_fee || 0), 0);
                const totalShipping = sales.reduce(
                    (sum, s) => sum + (s.seller_shipping_cost || s.shipping_cost || 0),
                    0,
                );
                const totalExpenses = purchases.reduce((sum, p) => sum + (p.amount || p.total_amount || 0), 0);

                headers = ['Category', 'Amount'];
                data = [
                    ['Revenue', totalRevenue.toFixed(2)],
                    ['Cost of Goods Sold', totalCOGS.toFixed(2)],
                    ['Gross Profit', (totalRevenue - totalCOGS).toFixed(2)],
                    ['Platform Fees', totalFees.toFixed(2)],
                    ['Shipping Costs', totalShipping.toFixed(2)],
                    ['Other Expenses', totalExpenses.toFixed(2)],
                    ['Net Profit', (totalRevenue - totalCOGS - totalFees - totalShipping - totalExpenses).toFixed(2)],
                ];
                filename = 'profit_loss';
                break;
        }

        if (data.length === 0) {
            toast.warning('No data to export for this report type');
            return;
        }

        // Generate CSV
        const csv = [headers.join(','), ...data.map((row) => row.map((cell) => '"' + cell + '"').join(','))].join(
            '\\n',
        );
        const blob = new Blob([csv], { type: 'text/csv' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = filename + '_' + toLocalDate(new Date()) + '.csv';
        a.click();
        URL.revokeObjectURL(url);
        toast.success('Report generated: ' + filename);
    },

    changeAnalyticsPeriod: async function (period) {
        const picker = document.getElementById('custom-date-picker');

        if (period === 'custom') {
            if (picker) picker.classList.remove('hidden');
            return;
        }

        if (picker) picker.classList.add('hidden');

        store.setState({ analyticsPeriod: period });

        // Immediately update period labels in the DOM so user sees change right away
        const periodLabels = {
            '7d': 'last 7 days',
            '30d': 'last 30 days',
            '90d': 'last 90 days',
            '6m': 'last 6 months',
            '1y': 'last year',
        };
        const label = periodLabels[period] || 'last 30 days';
        const descEl = document.querySelector('.page-description');
        if (descEl) descEl.textContent = 'Performance insights for ' + label;
        const periodTextEl = document.querySelector('.period-text');
        if (periodTextEl) periodTextEl.textContent = label.charAt(0).toUpperCase() + label.slice(1);
        const dropdown = document.getElementById('analytics-period');
        if (dropdown) dropdown.value = period;

        // Calculate date range based on period
        const now = new Date();
        let startDate = null;
        switch (period) {
            case '7d':
                startDate = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
                break;
            case '30d':
                startDate = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
                break;
            case '90d':
                startDate = new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000);
                break;
            case '6m':
                startDate = new Date(now.getTime() - 180 * 24 * 60 * 60 * 1000);
                break;
            case '1y':
                startDate = new Date(now.getTime() - 365 * 24 * 60 * 60 * 1000);
                break;
        }

        // Load analytics data with period filter
        await this.loadAnalytics();

        // Also load filtered sales for the analytics page
        if (startDate) {
            try {
                const salesData = await api.get('/sales', {
                    startDate: toLocalDate(startDate),
                });
                store.setState({ sales: salesData.sales || [] });
            } catch (error) {
                console.error('Failed to load filtered sales:', error);
                toast.error('Failed to load sales data');
            }
        }

        // Re-render page using renderApp for proper state handling
        if (store.state.currentPage === 'analytics') {
            renderApp(window.pages.analytics());
            // Force sync dropdown value after full re-render
            requestAnimationFrame(() => {
                const dd = document.getElementById('analytics-period');
                if (dd) dd.value = period;
            });
        }
    },

