    previewBankCSV: function (input) {
        const file = input.files[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = (e) => {
            const text = e.target.result;
            const lines = text.split('\n').filter((l) => l.trim());
            if (lines.length < 2) {
                toast.error('CSV appears empty');
                return;
            }
            const headers = lines[0].split(',').map((h) => h.trim().replace(/^"|"$/g, ''));
            store.setState({ _bankCsvRaw: text, _bankCsvHeaders: headers });

            // Build column selectors
            const makeOptions = (preferred) =>
                headers
                    .map(
                        (h, i) =>
                            `<option value="${i}" ${preferred.some((p) => h.toLowerCase().includes(p)) ? 'selected' : ''}>${h}</option>`,
                    )
                    .join('');
            document.getElementById('bank-col-date').innerHTML = sanitizeHTML(makeOptions(['date'])); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
            document.getElementById('bank-col-desc').innerHTML = sanitizeHTML(
                makeOptions(['desc', 'name', 'memo', 'payee', 'merchant']),
            ); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
            document.getElementById('bank-col-amount').innerHTML = sanitizeHTML(
                makeOptions(['amount', 'debit', 'credit', 'sum']),
            ); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method

            // Preview table
            const previewRows = lines.slice(1, 6).map((l) => l.split(',').map((c) => c.trim().replace(/^"|"$/g, '')));
            let table =
                '<table style="width: 100%; border-collapse: collapse;"><thead><tr>' +
                headers
                    .map(
                        (h) =>
                            `<th style="border: 1px solid var(--gray-200); padding: 4px 6px; font-weight: 600;">${escapeHtml(h)}</th>`,
                    )
                    .join('') +
                '</tr></thead><tbody>';
            table += previewRows
                .map(
                    (row) =>
                        '<tr>' +
                        row
                            .map(
                                (c) =>
                                    `<td style="border: 1px solid var(--gray-200); padding: 4px 6px;">${escapeHtml(c)}</td>`,
                            )
                            .join('') +
                        '</tr>',
                )
                .join('');
            table += '</tbody></table>';
            document.getElementById('bank-csv-preview-content').innerHTML = sanitizeHTML(table); // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
            document.getElementById('bank-csv-count').textContent = `${lines.length - 1} rows detected`;
            document.getElementById('bank-csv-preview').style.display = 'block';
            document.getElementById('bank-import-btn').style.display = 'block';
        };
        reader.readAsText(file);
    },

    importBankCSV: async function () {
        const raw = store.state._bankCsvRaw;
        if (!raw) {
            toast.error('No CSV loaded');
            return;
        }
        const headers = store.state._bankCsvHeaders || [];
        const dateCol = parseInt(document.getElementById('bank-col-date')?.value) || 0;
        const descCol = parseInt(document.getElementById('bank-col-desc')?.value) || 1;
        const amountCol = parseInt(document.getElementById('bank-col-amount')?.value) || 2;

        const lines = raw
            .split('\n')
            .filter((l) => l.trim())
            .slice(1); // skip header
        const purchases = [];
        let skipped = 0;
        for (const line of lines) {
            const cols = line.split(',').map((c) => c.trim().replace(/^"|"$/g, ''));
            const rawAmount = parseFloat((cols[amountCol] || '').replace(/[^0-9.\-]/g, ''));
            if (isNaN(rawAmount)) {
                skipped++;
                continue;
            }
            if (rawAmount >= 0) {
                skipped++;
                continue;
            } // skip credits/income
            purchases.push({
                vendorName: cols[descCol] || 'Bank Import',
                purchaseDate: cols[dateCol] || new Date().toISOString().slice(0, 10),
                items: [{ description: cols[descCol] || 'Import', quantity: 1, unitCost: Math.abs(rawAmount) }],
                paymentMethod: 'Bank',
                notes: 'Imported from bank CSV',
                status: 'completed',
            });
        }
        if (purchases.length === 0) {
            toast.error('No expense rows found (only credits/income were detected)');
            return;
        }

        const btn = document.getElementById('bank-import-btn');
        if (btn) {
            btn.disabled = true;
            btn.textContent = 'Importing...';
        }
        let imported = 0;
        for (const p of purchases) {
            try {
                await api.post('/financials/purchases', p);
                imported++;
            } catch {
                skipped++;
            }
        }
        await handlers.loadPurchases();
        toast.success(`Imported ${imported} expense transactions (${skipped} skipped)`);
        modals.close();
        if (store.state.currentPage === 'transactions') renderApp(window.pages.transactions());
    },

