    // Show add tag modal for transactions,

    showAddTagModal: function (transactionId) {
        const defaultTags = ['High Priority', 'Refund', 'Wholesale', 'Bundle', 'Custom'];
        const customTags = store.state.customTransactionTags || [];
        const salesTags = (store.state.sales || []).flatMap((s) => s.tags || []);
        const allTags = [...new Set([...defaultTags, ...customTags, ...salesTags])];

        // Find the transaction
        const sales = store.state.sales || [];
        const transaction = sales.find((s) => s.id === transactionId);
        const currentTags = transaction?.tags || [];

        const tagColors = {
            'High Priority': '#ef4444',
            Refund: '#f59e0b',
            Wholesale: '#3b82f6',
            Bundle: '#f59e0b',
            Custom: '#6b7280',
        };

        modals.show(`
            <div class="modal-header">
                <h2 class="modal-title">${components.icon('tag', 20)} Manage Tags</h2>
                <button class="modal-close" aria-label="Close" onclick="modals.close()">${components.icon('close')}</button>
            </div>
            <div class="modal-body">
                <div class="mb-4">
                    <div class="text-sm text-gray-600 mb-2">Transaction: ${escapeHtml(transaction?.listing_title || transaction?.inventory_title || 'Unknown')}</div>
                    <div class="text-xs text-gray-400">C$${(transaction?.sale_price || 0).toFixed(2)} on ${new Date(transaction?.created_at).toLocaleDateString()}</div>
                </div>

                <div class="form-group">
                    <p class="form-label">Select Tags</p>
                    <div style="display: flex; flex-wrap: wrap; gap: 8px;">
                        ${allTags
                            .map((tag) => {
                                const isSelected = currentTags.includes(tag);
                                const color = tagColors[tag] || '#6b7280';
                                return `
                                <label style="display: flex; align-items: center; gap: 6px; padding: 8px 12px; border-radius: 20px; cursor: pointer; border: 2px solid ${isSelected ? color : 'var(--gray-200)'}; background: ${isSelected ? color + '15' : 'white'}; transition: all 0.2s;">
                                    <input aria-label="Tags" type="checkbox" name="tags" value="${tag}" ${isSelected ? 'checked' : ''} style="display: none;">
                                    <span style="width: 12px; height: 12px; border-radius: 50%; background: ${color};"></span>
                                    <span style="font-size: 13px; color: ${isSelected ? color : 'var(--gray-700)'}; font-weight: ${isSelected ? '600' : '400'};">${tag}</span>
                                </label>
                            `;
                            })
                            .join('')}
                    </div>
                </div>

                <div class="form-group mt-4">
                    <label class="form-label" for="new-custom-tag">Add Custom Tag</label>
                    <div style="display: flex; gap: 8px;">
                        <inputinput type="text" id="new-custom-tag" class="form-input" placeholder="Enter new tag name..." style="flex: 1;" list="tag-suggestions" autocomplete="off">
                        <datalist id="tag-suggestions">
                            ${allTags.map((t) => `<option value="${escapeHtml(t)}">`).join('')}
                        </datalist>
                        <button type="button" class="btn btn-secondary" onclick="handlers.addCustomTag()">Add</button>
                    </div>
                </div>
            </div>
            <div class="modal-footer">
                <button type="button" class="btn btn-secondary" onclick="modals.close()">Cancel</button>
                <button type="button" class="btn btn-primary" onclick="handlers.saveTransactionTags('${transactionId}')">${components.icon('check', 16)} Save Tags</button>
            </div>
        `);
    },

    // Add custom tag,

    addCustomTag: function () {
        const input = document.getElementById('new-custom-tag');
        const tagName = input?.value?.trim();
        if (!tagName) return;

        const customTags = store.state.customTransactionTags || [];
        if (!customTags.includes(tagName)) {
            customTags.push(tagName);
            store.setState({ customTransactionTags: customTags });
        }

        input.value = '';
        toast.success(`Tag "${tagName}" added`);
    },

    // Save transaction tags,

    saveTransactionTags: function (transactionId) {
        const checkboxes = document.querySelectorAll('input[name="tags"]:checked');
        const selectedTags = Array.from(checkboxes).map((cb) => cb.value);

        // Update the transaction in state
        const sales = [...(store.state.sales || [])];
        const saleIndex = sales.findIndex((s) => s.id === transactionId);

        if (saleIndex >= 0) {
            sales[saleIndex] = { ...sales[saleIndex], tags: selectedTags };
            store.setState({ sales });
            toast.success(`Tags updated (${selectedTags.length} tags)`);
        }

        modals.close();
        renderApp(window.pages.transactions());
    },

    submitAddPurchase: async function (event) {
        event.preventDefault();
        const formData = new FormData(event.target);

        const purchaseData = {
            vendorName: formData.get('vendorName'),
            purchaseDate: formData.get('purchaseDate'),
            items: [
                {
                    description: formData.get('itemDescription') || 'Purchase item',
                    quantity: parseInt(formData.get('quantity')) || 1,
                    unitCost: parseFloat(formData.get('amount')) || 0,
                },
            ],
            paymentMethod: formData.get('paymentMethod'),
            notes: formData.get('notes'),
            status: 'completed',
        };

        try {
            await api.ensureCSRFToken();
            await api.post('/financials/purchases', purchaseData);
            toast.success('Purchase added successfully');
            modals.close();

            // Reload purchases
            await handlers.loadPurchases();
            if (store.state.currentPage === 'transactions') {
                renderApp(window.pages.transactions());
            }
        } catch (error) {
            toast.error('Failed to add purchase: ' + error.message);
        }
    },

